typedef struct _KEYBOARD_INPUT_DATA {
USHORT UnitId;   USHORT MakeCode;   USHORT Flags;   USHORT Reserved;
ULONG  ExtraInformation;
} KEYBOARD_INPUT_DATA, *PKEYBOARD_INPUT_DATA;

typedef struct DIHIDFFINITINFO {   DWORD  dwSize;
LPWSTR pwszDeviceInterface;   GUID   GuidInstance;
} DIHIDFFINITINFO, *LPDIHIDFFINITINFO;
成员 dwSize
指定结构的大小（以字节为单位）。 在使用 结构之前，必须初始化此成员。 pwszDeviceInterface
指向以 null 结尾的 Unicode 字符串，该字符串标识设备的设备接口。 驱动程序可以将设
备接口传递给 CreateFile 函数，以获取对设备的访问权限。 GuidInstance
指定此设备的设备实例 GUID。
typedef struct DIJOYCONFIG {   DWORD          dwSize;
GUID           guidInstance;   JOYREGHWCONFIG hwc;
DWORD          dwGain;
WCHAR          wszType[MAX_JOYSTRING];
WCHAR          wszCallout[MAX_JOYSTRING];
GUID           guidGameport;} DIJOYCONFIG, *LPDIJOYCONFIG;
成员 dwSize
指定结构的大小（以字节为单位）。 必须先初始化此成员，然后才能使用结构。 guidInstance
指定游戏杆的实例 GUID。 hwc
游戏杆硬件配置。 dwGain
指定全局增益设置。 此值作为“主音量控件”应用于所有力回馈效果。 wszType[MAX_JOYSTRING]
游戏杆的操纵杆类型。 它必须是 IDirectInputJoyConfig8：：EnumTypes 枚举的值之一。
wszCallout[MAX_JOYSTRING] 游戏杆的标注驱动程序。
guidGameport
指定标识用于此游戏杆的游戏端口的 GUID。
typedef struct DIJOYTYPEINFO {
DWORD            dwSize;   JOYREGHWSETTINGS hws;
CLSID            clsidConfig;
WCHAR            wszDisplayName[MAX_JOYSTRING];
WCHAR            wszCallout[MAX_JOYSTICKOEMVXDNAME];   WCHAR            wszHardwareId[MAX_JOYSTRING];
DWORD            dwFlags1;   DWORD            dwFlags2;
WCHAR            wszMapFile[MAX_JOYSTRING];} DIJOYTYPEINFO, *LPDIJOYTYPEINFO;
成员 dwSize
指定结构的大小（以字节为单位）。 必须先初始化此成员，然后才能使用结构。 hws
游戏杆硬件设置。 clsidConfig
为游戏杆类型配置对象指定 CLSID。 将此 CLSID 传递给 CoCreateInstance 以创建配置对
象。 如果类型没有自定义配置，则此字段为零。 wszDisplayName[MAX_JOYSTRING]
游戏杆类型的显示名称。 显示名称是用于向最终用户显示游戏杆类型的名称的名称。 wszCallout[MAX_JOYSTICKOEMVXDNAME]
负责处理此类型设备的轮询的设备。 如果要使用全局轮询标注，则这是一个 null 字符串。
wszHardwareId[MAX_JOYSTRING]
游戏杆类型的硬件 ID。 Windows 2000 和 Windows 98 上的即插即用硬件 ID (DirectX 7.0
仅) 来查找游戏杆的驱动程序。 dwFlags1
游戏杆类型标志。 可以将此成员设置为以下标志的组合。

