ULONG  ExtraInformation;
} MOUSE_INPUT_DATA, *PMOUSE_INPUT_DATA;

typedef struct DIFFDEVICEATTRIBUTES {   DWORD dwFlags;
DWORD dwFFSamplePeriod;
DWORD dwFFMinTimeResolution;
} DIFFDEVICEATTRIBUTES, *LPDIFFDEVICEATTRIBUTES;
成员 dwFlags
保留供将来使用。 此成员必须设置为零。 dwFFSamplePeriod
指定播放强制命令之间的最短时间（以微秒为单位）。 dwFFMinTimeResolution
指定设备可以解析的最短时间，以微秒为单位。 设备将任意时间值舍入为最接近的受支持增量。 例如，如果 dwFFMinTimeResolution 的值为 1000，则设备将随时舍入到最接
近的毫秒。
typedef struct DIFFOBJECTATTRIBUTES {   DWORD dwFFMaxForce;
DWORD dwFFForceResolution;
} DIFFOBJECTATTRIBUTES, *LPDIFFOBJECTATTRIBUTES;
成员 dwFFMaxForce
指定由与此对象关联的执行器可以创建的最大力的幅度。 力以牛顿表示，并相对于在设备 正常 操作期间手部的位置进行测量。 如果此成员为零，则假定对象不支持力回馈。
dwFFForceResolution
指定与此对象关联的执行器的力分辨率。 返回的值表示力回馈系统可表示的最大力的等
级或细分数，从 0 (无力) 到最大力。

HRESULT SendForceFeedbackCommand(
  DWORD dwDeviceID,
  DWORD dwCommand
);

HRESULT SendNotify();

Return value:
If successful, returns DI_OK. Otherwise returns COM error values (list not exhaustive).
